    else:
        return price

test.actualResponse:
import pytest

def test_vip_discount():
    assert calculate_discount(100, 'vip') == 80.0

def test_regular_discount():
    assert calculate_discount(100, 'regular') == 95.0

def test_no_discount():
    assert calculate_discount(100, 'unknown') == 100

def test_zero_price():
    assert calculate_discount(0, 'vip') == 0.0

def test_negative_price():
    assert calculate_discount(-50, 'vip') == -40.0

